const crypto = require('crypto');

/**
 * Generates a cryptographically secure random token for password reset links.
 *
 * @param {number} [length=32] - The number of random bytes to generate (the resulting
 *   hex string will be twice this length).
 * @returns {Promise<string>} A promise that resolves to a hex-encoded secure random token.
 */
function generatePasswordResetToken(length = 32) {
  return new Promise((resolve, reject) => {
    if (!Number.isInteger(length) || length < 16) {
      return reject(
        new Error('Token length must be an integer of at least 16 bytes to ensure sufficient entropy.')
      );
    }

    crypto.randomBytes(length, (err, buffer) => {
      if (err) {
        return reject(new Error(`Failed to generate secure random bytes: ${err.message}`));
      }
      resolve(buffer.toString('hex'));
    });
  });
}

/**
 * Generates a cryptographically secure random token (synchronous version).
 *
 * @param {number} [length=32] - The number of random bytes to generate.
 * @returns {string} A hex-encoded secure random token.
 */
function generatePasswordResetTokenSync(length = 32) {
  if (!Number.isInteger(length) || length < 16) {
    throw new Error('Token length must be an integer of at least 16 bytes to ensure sufficient entropy.');
  }

  const buffer = crypto.randomBytes(length);
  return buffer.toString('hex');
}

/**
 * Generates a URL-safe base64-encoded token suitable for use in password reset URLs.
 *
 * @param {number} [length=32] - The number of random bytes to generate.
 * @returns {Promise<string>} A promise that resolves to a URL-safe base64-encoded token.
 */
function generateUrlSafeToken(length = 32) {
  return new Promise((resolve, reject) => {
    if (!Number.isInteger(length) || length < 16) {
      return reject(
        new Error('Token length must be an integer of at least 16 bytes to ensure sufficient entropy.')
      );
    }

    crypto.randomBytes(length, (err, buffer) => {
      if (err) {
        return reject(new Error(`Failed to generate secure random bytes: ${err.message}`));
      }
      // Convert to base64 and make it URL-safe by replacing +, /, and removing =
      const token = buffer
        .toString('base64')
        .replace(/\+/g, '-')
        .replace(/\//g, '_')
        .replace(/=/g, '');
      resolve(token);
    });
  });
}

/**
 * Creates a hashed version of the token for secure storage in the database.
 * The plain token is sent to the user; the hashed version is stored server-side.
 *
 * @param {string} token - The plain-text token to hash.
 * @returns {string} A SHA-256 hex digest of the token.
 */
function hashTokenForStorage(token) {
  if (!token || typeof token !== 'string') {
    throw new Error('A valid token string is required for hashing.');
  }
  return crypto.createHash('sha256').update(token, 'utf8').digest('hex');
}

/**
 * Generates a complete password reset token pair: the plain token (to send to the user)
 * and the hashed token (to store in the database), along with an expiration timestamp.
 *
 * @param {Object} [options] - Configuration options.
 * @param {number} [options.byteLength=32] - Number of random bytes for the token.
 * @param {number} [options.expiresInMinutes=60] - Token validity duration in minutes.
 * @returns {Promise<Object>} An object containing plainToken, hashedToken, and expiresAt.
 */
async function createPasswordResetTokenPair(options = {}) {
  const { byteLength = 32, expiresInMinutes = 60 } = options;

  const plainToken = await generateUrlSafeToken(byteLength);
  const hashedToken = hashTokenForStorage(plainToken);
  const expiresAt = new Date(Date.now() + expiresInMinutes * 60 * 1000);

  return {
    plainToken,   // Send this to the user via email
    hashedToken,  // Store this in the database
    expiresAt     // Store this alongside the hashed token for expiration checks
  };
}

